const pllDescription={init:()=>{pllDescriptionData&&("loading"!==document.readyState?pllDescription.ready():document.addEventListener("DOMContentLoaded",pllDescription.ready))},ready:()=>{const t=document.getElementById("description");if(!t)return;const e=[];pllDescriptionData.forEach(i=>{const n=document.createElement("div");n.setAttribute("lang",i.lang);const r=document.createElement("label");if(r.setAttribute("for",`description_${i.slug}`),r.setAttribute("dir",i.direction),i.flag.src){const t=document.createElement("img");t.setAttribute("alt",""),t.setAttribute("src",i.flag.src),i.flag.width&&t.setAttribute("width",i.flag.width),i.flag.height&&t.setAttribute("height",i.flag.height),r.textContent=` ${i.name}`,r.prepend(t)}else r.textContent=i.name;const c=t.cloneNode(!0);c.setAttribute("id",`description_${i.slug}`),c.setAttribute("name",`description_${i.slug}`),c.setAttribute("dir",i.direction),c.innerHTML=i.description,n.append(r,document.createElement("br"),c),e.push(n)}),t.replaceWith(...e)}};pllDescription.init();